(function(){
'use strict';

const DATA=window.PROMPTLA_DATA||{prompts:[],categories:{},collections:{},models:[]};
const body=document.body;
const PAGE=body?.dataset.page||'detail';
const ROOT=body?.dataset.root||'';
const SITE_URL='https://promptla.page.gd/';
const DEMO_ADMIN={email:'admin@promptla.local',password:'PromptlaDemo2026!'};
const KEYS={
 users:'promptla_v2_users',session:'promptla_v2_session',likes:'promptla_v2_likes',saves:'promptla_v2_saves',copies:'promptla_v2_copies',
 customPrompts:'promptla_v2_custom_prompts',deletedPrompts:'promptla_v2_deleted_prompts',remixes:'promptla_v2_remixes',collections:'promptla_v2_collections',
 posts:'promptla_v2_posts',messages:'promptla_v2_messages',promptComments:'promptla_v2_prompt_comments',reports:'promptla_v2_reports',settings:'promptla_v2_settings',recent:'promptla_v2_recent'
};

function esc(v){return String(v??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#039;','"':'&quot;'}[c]));}
function attr(v){return esc(v).replace(/`/g,'&#096;');}
function path(p){p=String(p||''); if(!p||/^(https?:|data:|blob:|#|mailto:|tel:)/i.test(p)) return p; if(p.startsWith('../')) return p; return ROOT+p.replace(/^\//,'');}
function page(p){return ROOT+p;}
function now(){return new Date().toISOString();}
function uid(prefix='id'){return prefix+'-'+Date.now().toString(36)+'-'+Math.random().toString(36).slice(2,8);}
function read(key,fallback){try{const v=localStorage.getItem(key);return v?JSON.parse(v):fallback;}catch(e){return fallback;}}
function write(key,value){try{localStorage.setItem(key,JSON.stringify(value));return true;}catch(e){window.showSiteToast?.('Tarayıcı depolama alanı dolu. Bazı veriler kaydedilemedi.','error');return false;}}
function hashPassword(s){let h=2166136261; for(let i=0;i<String(s).length;i++){h^=String(s).charCodeAt(i);h=Math.imul(h,16777619);} return (h>>>0).toString(16);}
function toast(m,t='success'){window.showSiteToast?window.showSiteToast(m,t):alert(m);}
function fmtDate(s){try{return new Intl.DateTimeFormat('tr-TR',{dateStyle:'medium'}).format(new Date(s));}catch(e){return s||'';}}
function initials(name){return String(name||'P').trim().split(/\s+/).slice(0,2).map(x=>x[0]).join('').toUpperCase();}
function categoryLabel(cat){return DATA.categories?.[cat]?.label||cat||'Genel';}
function getUsers(){return read(KEYS.users,[]);} function setUsers(v){write(KEYS.users,v);}
function currentUser(){const id=read(KEYS.session,null); return getUsers().find(u=>u.id===id)||null;}
function requireUser(action){const u=currentUser(); if(u) return u; toast(action+' için giriş yapmalısın.','error'); window.openAuthModal?.('login'); return null;}
function userSet(key,userId){const all=read(key,{}); return new Set(all[userId]||[]);}
function saveUserSet(key,userId,set){const all=read(key,{});all[userId]=[...set];write(key,all);}
function copyCounts(){return read(KEYS.copies,{});}
function combinedPrompts(){const deleted=new Set(read(KEYS.deletedPrompts,[]));return [...DATA.prompts,...read(KEYS.customPrompts,[])].filter(p=>!deleted.has(String(p.id)));}
function findPrompt(slugOrId){return combinedPrompts().find(p=>p.slug===slugOrId||String(p.id)===String(slugOrId));}
function promptUrl(p){return page('prompt-detay.html?slug='+encodeURIComponent(p.slug));}
function replaceVars(text,values){return String(text||'').replace(/\[([A-Z0-9_]+)\]/g,(m,k)=>values[k]||m);}
function activeVersionLabel(v){return v==='expert'?'Uzman':v==='advanced'?'Gelişmiş':'Hızlı';}

function seed(){
  const users=getUsers();
  if(!users.length){
    setUsers([{id:'local-admin',name:'Demo Yönetici',email:DEMO_ADMIN.email,passwordHash:hashPassword(DEMO_ADMIN.password),role:'admin',bio:'PROMPTLA yerel demo yöneticisi',createdAt:now()}]);
  }
  if(!localStorage.getItem(KEYS.posts)){
    const seedPosts=[
      {id:'post-seed-1',userId:'system',author:'PROMPTLA Editör',type:'prompt',content:'Haftanın promptu: Profesyonel Logo Mockup Sahnesi. Logo yazısını, yüzeyi ve ışığı değiştirerek kendi marka sunumunu oluşturabilirsin.',tool:'ChatGPT Images / Midjourney',promptId:8,outputText:'Gerçekçi metal tabela üzerinde PROMPTLA logo sunumu',image:'images/urun1.webp',likes:[],saves:[],reports:[],status:'active',createdAt:'2026-07-21T09:00:00',comments:[]},
      {id:'post-seed-2',userId:'system',author:'PROMPTLA Topluluk',type:'output',content:'Kod hata ayıklama promptunda “mevcut yapıyı bozma” kısıtı, modelin tüm projeyi gereksiz yere yeniden yazmasını ciddi şekilde azaltıyor.',tool:'ChatGPT',promptId:1,outputText:'Kök neden + minimal kod yaması + test listesi',image:'',likes:[],saves:[],reports:[],status:'active',createdAt:'2026-07-20T17:30:00',comments:[]},
      {id:'post-seed-3',userId:'system',author:'PROMPTLA Lab',type:'tip',content:'İyi bir görsel promptta konu, ortam, kamera, ışık, malzeme ve oranı ayrı ayrı tanımla. Değişmesini istemediğin alanları negatif kısıt olarak ekle.',tool:'Genel',promptId:null,outputText:'',image:'images/prompt1.webp',likes:[],saves:[],reports:[],status:'active',createdAt:'2026-07-19T12:00:00',comments:[]}
    ]; write(KEYS.posts,seedPosts);
  }
  if(!localStorage.getItem(KEYS.settings)) write(KEYS.settings,{weeklyPromptId:8,siteLogoText:'PROMPT',siteLogoAccent:'LA'});
}

function applySeo(title,description,canonical,ogImage){
  if(title) document.title=title;
  const ensure=(selector,tag,attrs)=>{let el=document.querySelector(selector);if(!el){el=document.createElement(tag);Object.entries(attrs).forEach(([k,v])=>el.setAttribute(k,v));document.head.appendChild(el);}return el;};
  const desc=ensure('meta[name="description"]','meta',{name:'description'}); if(description) desc.content=description;
  const can=ensure('link[rel="canonical"]','link',{rel:'canonical'}); can.href=canonical||SITE_URL;
  const ogt=ensure('meta[property="og:title"]','meta',{property:'og:title'}); ogt.content=title||document.title;
  const ogd=ensure('meta[property="og:description"]','meta',{property:'og:description'}); ogd.content=description||'';
  const ogu=ensure('meta[property="og:url"]','meta',{property:'og:url'}); ogu.content=canonical||SITE_URL;
  const ogi=ensure('meta[property="og:image"]','meta',{property:'og:image'}); ogi.content=ogImage||SITE_URL+'images/urun1.webp';
  ensure('meta[property="og:type"]','meta',{property:'og:type'}).content='website';
}

function renderAuthModal(){
  if(document.getElementById('authModal')) return;
  document.body.insertAdjacentHTML('beforeend',`<div id="authModal" class="modal" aria-hidden="true"><div class="modal-content"><button class="close-btn" type="button" aria-label="Kapat" onclick="closeAuthModal()">×</button><div class="auth-tabs"><button class="tab-btn active" id="tab-login" type="button" onclick="switchAuthTab('login')">Giriş Yap</button><button class="tab-btn" id="tab-register" type="button" onclick="switchAuthTab('register')">Kayıt Ol</button></div><form id="loginForm" class="auth-form active"><div class="divider"><span>yerel hesap</span></div><label>E-posta<input type="email" name="email" required autocomplete="email"></label><label>Şifre<input type="password" name="password" required autocomplete="current-password"></label><button class="btn btn-full" type="submit">Giriş Yap</button><small class="auth-note">Veriler yalnızca bu tarayıcıda saklanır.</small></form><form id="registerForm" class="auth-form"><div class="divider"><span>yeni yerel hesap</span></div><label>Ad Soyad<input type="text" name="name" required maxlength="60"></label><label>E-posta<input type="email" name="email" required autocomplete="email"></label><label>Şifre<input type="password" name="password" minlength="8" required autocomplete="new-password"></label><button class="btn btn-full" type="submit">Kayıt Ol</button><small class="auth-note">Yeni hesaplar her zaman standart kullanıcı rolü alır.</small></form></div></div>`);
  bindAuthForms();
}
window.openAuthModal=function(tab='login'){renderAuthModal();window.switchAuthTab(tab);const m=document.getElementById('authModal');m.style.display='flex';m.setAttribute('aria-hidden','false');};
window.closeAuthModal=function(){const m=document.getElementById('authModal');if(m){m.style.display='none';m.setAttribute('aria-hidden','true');}};
window.switchAuthTab=function(tab){document.querySelectorAll('#authModal .tab-btn').forEach(x=>x.classList.toggle('active',x.id==='tab-'+tab));document.querySelectorAll('#authModal .auth-form').forEach(x=>x.classList.toggle('active',x.id===(tab==='login'?'loginForm':'registerForm')));};
function login(email,password){const u=getUsers().find(x=>x.email.toLowerCase()===String(email).toLowerCase());if(!u||u.passwordHash!==hashPassword(password)) return false;write(KEYS.session,u.id);return true;}
function register(name,email,password){const users=getUsers();if(users.some(x=>x.email.toLowerCase()===email.toLowerCase())) return {ok:false,message:'Bu e-posta ile kayıtlı bir yerel hesap var.'};const u={id:uid('user'),name:name.trim(),email:email.trim().toLowerCase(),passwordHash:hashPassword(password),role:'user',bio:'',createdAt:now()};users.push(u);setUsers(users);write(KEYS.session,u.id);return {ok:true,user:u};}
function bindAuthForms(){
  document.getElementById('loginForm')?.addEventListener('submit',e=>{e.preventDefault();const fd=new FormData(e.currentTarget);if(login(fd.get('email'),fd.get('password'))){toast('Giriş yapıldı.');window.closeAuthModal();renderHeader();renderCurrentPage();}else toast('E-posta veya şifre hatalı.','error');});
  document.getElementById('registerForm')?.addEventListener('submit',e=>{e.preventDefault();const fd=new FormData(e.currentTarget);const p=String(fd.get('password'));if(p.length<8){toast('Şifre en az 8 karakter olmalı.','error');return;}const r=register(String(fd.get('name')),String(fd.get('email')),p);if(!r.ok){toast(r.message,'error');return;}toast('Yerel hesabın oluşturuldu.');window.closeAuthModal();renderHeader();renderCurrentPage();});
}

function renderHeader(){
  const settings=read(KEYS.settings,{});document.querySelectorAll('[data-logo-text]').forEach(x=>x.textContent=settings.siteLogoText||'PROMPT');document.querySelectorAll('[data-logo-accent]').forEach(x=>x.textContent=settings.siteLogoAccent||'LA');
  document.querySelectorAll('.hamburger').forEach(btn=>{btn.setAttribute('role','button');btn.setAttribute('tabindex','0');btn.setAttribute('aria-label','Menüyü aç');btn.setAttribute('aria-expanded','false');btn.addEventListener('keydown',e=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();window.toggleMenu();}});});
  document.querySelectorAll('.nav-submenu').forEach(menu=>{
    if(!menu.querySelector('[data-added="builder"]')) menu.insertAdjacentHTML('beforeend',`<a data-added="builder" href="${page('prompt-builder.html')}">Prompt Builder</a><a data-added="collections" href="${page('koleksiyonlar.html')}">Koleksiyonlar</a><a data-added="guide" href="${page('rehber.html')}">Prompt Rehberi</a>`);
  });
  const slot=document.getElementById('accountMenuSlot'); if(!slot) return; const u=currentUser();
  if(u){slot.innerHTML=`<button class="account-btn account-btn-with-photo" onclick="toggleDropdown(event)" type="button"><span class="account-name">${esc(u.name.split(' ')[0])}</span><span class="account-avatar-sm">${esc(initials(u.name))}</span></button><div class="account-dropdown" id="accountDropdown"><a href="${page('profil.html')}">Profilim</a>${u.role==='admin'?`<a href="${page('admin.html')}">Yerel Yönetim</a>`:''}<a href="#" data-local-logout>Çıkış Yap</a></div>`;}
  else{slot.innerHTML=`<button class="account-btn" onclick="toggleDropdown(event)" type="button">Hesap</button><div class="account-dropdown" id="accountDropdown"><a href="#" onclick="openAuthModal('login');return false;">Giriş Yap</a><a href="#" onclick="openAuthModal('register');return false;">Kayıt Ol</a></div>`;}
  slot.querySelector('[data-local-logout]')?.addEventListener('click',e=>{e.preventDefault();localStorage.removeItem(KEYS.session);toast('Çıkış yapıldı.');renderHeader();renderCurrentPage();});
}

function togglePromptAction(promptId,type){const u=requireUser(type==='like'?'Beğenme':'Kaydetme');if(!u)return null;const key=type==='like'?KEYS.likes:KEYS.saves;const set=userSet(key,u.id);const id=String(promptId);if(set.has(id))set.delete(id);else set.add(id);saveUserSet(key,u.id,set);return set.has(id);}
function promptMetrics(id){const users=getUsers();let likes=0,saves=0;const l=read(KEYS.likes,{}),s=read(KEYS.saves,{});users.forEach(u=>{if((l[u.id]||[]).includes(String(id)))likes++;if((s[u.id]||[]).includes(String(id)))s++;});return {likes,saves,copies:Number(copyCounts()[id]||0)};}
async function copyPrompt(prompt,version='quick',values={}){const text=replaceVars(prompt.versions[version],values);const ok=await window.promptlaCopyText(text);if(ok){const c=copyCounts();c[prompt.id]=Number(c[prompt.id]||0)+1;write(KEYS.copies,c);}return ok;}
function markRecent(prompt){const list=read(KEYS.recent,[]).filter(x=>x!==prompt.id);list.unshift(prompt.id);write(KEYS.recent,list.slice(0,10));}

function promptCard(p){const u=currentUser();const liked=u?userSet(KEYS.likes,u.id).has(String(p.id)):false;const saved=u?userSet(KEYS.saves,u.id).has(String(p.id)):false;const m=promptMetrics(p.id);return `<article class="prompt-card-modern prompt-card-v2" data-category="${attr(p.category)}" data-prompt-id="${attr(p.id)}"><a class="prompt-card-image" href="${attr(promptUrl(p))}"><img src="${attr(path(p.thumbnail||p.image))}" alt="${attr(p.title)}" loading="lazy" width="640" height="360"><span class="prompt-level-badge">${esc(p.level)}</span></a><div class="prompt-card-content"><div class="prompt-card-meta"><span>${esc(categoryLabel(p.category))}</span><span>${esc(p.subcategory)}</span></div><h3><a href="${attr(promptUrl(p))}">${esc(p.title)}</a></h3><p class="prompt-card-description">${esc(p.description)}</p><div class="prompt-model-tags">${p.models.slice(0,3).map(x=>`<span>${esc(x)}</span>`).join('')}</div><div class="prompt-stat-row"><span>♡ ${m.likes}</span><span>☆ ${m.saves}</span><span>⧉ ${m.copies}</span></div><div class="profile-action-row prompt-card-actions"><button class="mini-action-btn ${liked?'active':''}" data-prompt-like="${attr(p.id)}" type="button">${liked?'♥ Beğenildi':'♡ Beğen'}</button><button class="mini-action-btn ${saved?'active':''}" data-prompt-save="${attr(p.id)}" type="button">${saved?'★ Kaydedildi':'☆ Kaydet'}</button><button class="mini-action-btn" data-prompt-copy="${attr(p.id)}" type="button">⧉ Hızlı Kopyala</button><a class="mini-action-btn" href="${attr(promptUrl(p))}">Aç</a></div></div></article>`;}

let libraryState={search:'',category:'all',subcategory:'all',model:'all',level:'all',sort:'featured',page:1,pageSize:12};
function filteredPrompts(){let list=combinedPrompts();const s=libraryState.search.toLocaleLowerCase('tr-TR').trim();if(s)list=list.filter(p=>[p.title,p.description,p.subcategory,...p.tags,...p.models].join(' ').toLocaleLowerCase('tr-TR').includes(s));if(libraryState.category!=='all')list=list.filter(p=>p.category===libraryState.category);if(libraryState.subcategory!=='all')list=list.filter(p=>p.subcategory===libraryState.subcategory);if(libraryState.model!=='all')list=list.filter(p=>p.models.includes(libraryState.model));if(libraryState.level!=='all')list=list.filter(p=>p.level===libraryState.level);const sort=libraryState.sort;if(sort==='new')list.sort((a,b)=>String(b.createdAt).localeCompare(String(a.createdAt)));else if(sort==='copied')list.sort((a,b)=>promptMetrics(b.id).copies-promptMetrics(a.id).copies);else if(sort==='liked')list.sort((a,b)=>promptMetrics(b.id).likes-promptMetrics(a.id).likes);else if(sort==='az')list.sort((a,b)=>a.title.localeCompare(b.title,'tr'));else list.sort((a,b)=>(Number(b.featured)-Number(a.featured))||a.id-b.id);return list;}
function renderLibrary(){const grid=document.getElementById('promptGrid');if(!grid)return;const list=filteredPrompts();const pages=Math.max(1,Math.ceil(list.length/libraryState.pageSize));libraryState.page=Math.min(libraryState.page,pages);const slice=list.slice((libraryState.page-1)*libraryState.pageSize,libraryState.page*libraryState.pageSize);grid.innerHTML=slice.map(promptCard).join('')||'<div class="profile-empty-state">Bu filtrelerle eşleşen prompt bulunamadı.</div>';const count=document.getElementById('promptResultCount');if(count)count.textContent=`${list.length} prompt bulundu`;const pag=document.getElementById('promptPagination');if(pag)pag.innerHTML=`<button class="mini-action-btn" data-page-prev ${libraryState.page===1?'disabled':''}>← Önceki</button><span>${libraryState.page} / ${pages}</span><button class="mini-action-btn" data-page-next ${libraryState.page===pages?'disabled':''}>Sonraki →</button>`;}
function initPromptLibrary(){
  const params=new URLSearchParams(location.search);libraryState.category=params.get('cat')||'all';
  const controls=document.getElementById('promptFilters');if(controls){
    const categories=Object.entries(DATA.categories).map(([k,v])=>`<option value="${attr(k)}" ${libraryState.category===k?'selected':''}>${esc(v.label)}</option>`).join('');
    const subs=[...new Set(combinedPrompts().map(p=>p.subcategory))].sort((a,b)=>a.localeCompare(b,'tr')).map(x=>`<option>${esc(x)}</option>`).join('');
    const models=[...new Set(combinedPrompts().flatMap(p=>p.models))].sort().map(x=>`<option>${esc(x)}</option>`).join('');
    controls.innerHTML=`<div class="prompt-search-box"><label for="promptSearch">Prompt ara</label><input id="promptSearch" type="search" placeholder="Örn. PHP hata ayıklama, ürün reklamı..."></div><label>Kategori<select id="categoryFilter"><option value="all">Tüm kategoriler</option>${categories}</select></label><label>Alt kategori<select id="subcategoryFilter"><option value="all">Tüm alt kategoriler</option>${subs}</select></label><label>Model<select id="modelFilter"><option value="all">Tüm modeller</option>${models}</select></label><label>Seviye<select id="levelFilter"><option value="all">Tüm seviyeler</option><option>Başlangıç</option><option>Orta</option><option>İleri</option></select></label><label>Sırala<select id="sortFilter"><option value="featured">Öne çıkan</option><option value="new">En yeni</option><option value="copied">En çok kopyalanan</option><option value="liked">En çok beğenilen</option><option value="az">A–Z</option></select></label>`;
    [['promptSearch','search'],['categoryFilter','category'],['subcategoryFilter','subcategory'],['modelFilter','model'],['levelFilter','level'],['sortFilter','sort']].forEach(([id,key])=>document.getElementById(id)?.addEventListener(id==='promptSearch'?'input':'change',e=>{libraryState[key]=e.target.value;libraryState.page=1;renderLibrary();}));
  }
  renderLibrary();
  document.getElementById('promptPagination')?.addEventListener('click',e=>{if(e.target.closest('[data-page-prev]'))libraryState.page--;if(e.target.closest('[data-page-next]'))libraryState.page++;renderLibrary();document.getElementById('prompt-library')?.scrollIntoView({behavior:'smooth'});});
  document.addEventListener('click',async e=>{const like=e.target.closest('[data-prompt-like]'),save=e.target.closest('[data-prompt-save]'),copy=e.target.closest('[data-prompt-copy]');if(like){togglePromptAction(like.dataset.promptLike,'like');renderLibrary();}if(save){togglePromptAction(save.dataset.promptSave,'save');renderLibrary();}if(copy){const p=findPrompt(copy.dataset.promptCopy);if(p){const vals=Object.fromEntries(p.variables.map(v=>[v.key,v.default]));await copyPrompt(p,'quick',vals);renderLibrary();}}});
}

function builderMarkup(p,standalone=false){const defaults=Object.fromEntries(p.variables.map(v=>[v.key,v.default]));return `<div class="prompt-builder-shell" data-builder-id="${attr(p.id)}"><div class="builder-top"><div><span class="eyebrow">DOLDURULABİLİR PROMPT BUILDER</span><h2>${esc(standalone?'Promptunu özelleştir':'Canlı prompt oluştur')}</h2><p>Alanları değiştir; önizleme anında güncellensin.</p></div><div class="version-switch" role="tablist"><button class="active" data-version="quick" type="button">Hızlı</button><button data-version="advanced" type="button">Gelişmiş</button><button data-version="expert" type="button">Uzman</button></div></div><div class="builder-grid"><form class="builder-fields">${p.variables.map(v=>`<label>${esc(v.label)}<textarea name="${attr(v.key)}" rows="2">${esc(v.default)}</textarea></label>`).join('')}</form><div class="builder-preview"><div class="builder-preview-head"><strong>Canlı Önizleme</strong><span data-version-label>Hızlı sürüm</span></div><textarea readonly data-builder-output>${esc(replaceVars(p.versions.quick,defaults))}</textarea><div class="builder-actions"><button class="btn" type="button" data-builder-copy>Promptu Kopyala</button><button class="btn btn-secondary" type="button" data-builder-save>Özel Sürümü Kaydet</button><button class="mini-action-btn" type="button" data-builder-share>Çıktı Olarak Paylaş</button></div></div></div></div>`;}
function bindBuilder(container,p){let version='quick';const fields=container.querySelector('.builder-fields');const output=container.querySelector('[data-builder-output]');const values=()=>Object.fromEntries(p.variables.map(v=>[v.key,fields.elements[v.key]?.value||'']));const refresh=()=>{output.value=replaceVars(p.versions[version],values());container.querySelector('[data-version-label]').textContent=activeVersionLabel(version)+' sürüm';};fields.addEventListener('input',refresh);container.querySelectorAll('[data-version]').forEach(btn=>btn.addEventListener('click',()=>{version=btn.dataset.version;container.querySelectorAll('[data-version]').forEach(x=>x.classList.toggle('active',x===btn));refresh();}));container.querySelector('[data-builder-copy]')?.addEventListener('click',async()=>{await copyPrompt(p,version,values());refreshDetailMetrics(p);});container.querySelector('[data-builder-save]')?.addEventListener('click',()=>{const u=requireUser('Özel sürüm kaydetme');if(!u)return;const remixes=read(KEYS.remixes,[]);remixes.unshift({id:uid('remix'),userId:u.id,promptId:p.id,title:p.title+' — '+activeVersionLabel(version)+' Remix',content:output.value,values:values(),version,createdAt:now()});write(KEYS.remixes,remixes);toast('Özel prompt sürümün profiline kaydedildi.');});container.querySelector('[data-builder-share]')?.addEventListener('click',()=>{const u=requireUser('Paylaşma');if(!u)return;sessionStorage.setItem('promptla_share_draft',JSON.stringify({promptId:p.id,content:p.title+' promptunu özelleştirdim.',tool:p.models[0],promptText:output.value}));location.href=page('sosyal.html?create=1');});refresh();}

function refreshDetailMetrics(p){const box=document.getElementById('detailMetrics');if(!box)return;const m=promptMetrics(p.id);box.innerHTML=`<span>♡ ${m.likes} beğeni</span><span>☆ ${m.saves} kayıt</span><span>⧉ ${m.copies} kopyalama</span>`;}
function renderPromptDetail(){const app=document.getElementById('promptDetailApp');if(!app)return;const slug=new URLSearchParams(location.search).get('slug');const p=findPrompt(slug);if(!p){app.innerHTML='<div class="profile-empty-state">Prompt bulunamadı. <a href="promptlar.html">Kütüphaneye dön</a></div>';return;}markRecent(p);applySeo(`${p.title} | PROMPTLA`,p.description,SITE_URL+'prompt-detay.html?slug='+encodeURIComponent(p.slug),SITE_URL+p.image);const u=currentUser();const liked=u?userSet(KEYS.likes,u.id).has(String(p.id)):false,saved=u?userSet(KEYS.saves,u.id).has(String(p.id)):false;app.innerHTML=`<section class="prompt-detail-hero"><div class="prompt-detail-copy"><div class="prompt-breadcrumb"><a href="${page('promptlar.html')}">Promptlar</a><span>/</span><span>${esc(categoryLabel(p.category))}</span></div><span class="eyebrow">${esc(p.subcategory)} • ${esc(p.level)}</span><h1>${esc(p.title)}</h1><p>${esc(p.description)}</p><div class="prompt-model-tags large">${p.models.map(x=>`<span>${esc(x)}</span>`).join('')}</div><div id="detailMetrics" class="prompt-detail-metrics"></div><div class="prompt-detail-actions"><button class="btn" data-detail-like type="button">${liked?'♥ Beğenildi':'♡ Beğen'}</button><button class="btn btn-secondary" data-detail-save type="button">${saved?'★ Kaydedildi':'☆ Kaydet'}</button><button class="mini-action-btn" data-add-collection type="button">＋ Koleksiyona Ekle</button><button class="mini-action-btn" data-report-prompt type="button">⚑ Raporla</button></div></div><div class="prompt-detail-image"><img src="${attr(path(p.image))}" alt="${attr(p.title)}" width="900" height="600"><div class="prompt-detail-tags">${p.tags.map(x=>`<span>#${esc(x)}</span>`).join('')}</div></div></section><section id="detailBuilder"></section><section class="prompt-learning-grid"><article class="detail-card"><span class="eyebrow">ÖNCE</span><h2>Zayıf prompt</h2><pre>${esc(p.before)}</pre></article><article class="detail-card is-good"><span class="eyebrow">SONRA</span><h2>Yapılandırılmış prompt</h2><pre>${esc(p.versions.advanced)}</pre></article></section><section class="prompt-detail-info"><article class="detail-card"><h2>Çıktı biçimi</h2><p>${esc(p.outputFormat)}</p></article><article class="detail-card"><h2>Kısıtlar</h2><p>${esc(p.constraints)}</p></article><article class="detail-card"><h2>Sürüm</h2><p>v${esc(p.version)} • Son güncelleme ${esc(fmtDate(p.createdAt))}</p></article></section><section class="prompt-comments-section"><div class="section-heading"><span class="eyebrow">TOPLULUK</span><h2>Yorumlar ve kullanım notları</h2></div><form id="promptCommentForm" class="comment-form"><textarea name="comment" required placeholder="Bu promptla aldığın sonucu veya önerini paylaş..."></textarea><button class="btn" type="submit">Yorum Ekle</button></form><div id="promptComments"></div></section><section class="related-prompts"><div class="section-heading"><span class="eyebrow">BENZER İÇERİK</span><h2>İlgili promptlar</h2></div><div class="prompt-grid-modern">${combinedPrompts().filter(x=>x.category===p.category&&x.id!==p.id).slice(0,3).map(promptCard).join('')}</div></section>`;
  const b=document.getElementById('detailBuilder');b.innerHTML=builderMarkup(p);bindBuilder(b,p);refreshDetailMetrics(p);renderPromptComments(p);
  app.querySelector('[data-detail-like]')?.addEventListener('click',()=>{togglePromptAction(p.id,'like');renderPromptDetail();});app.querySelector('[data-detail-save]')?.addEventListener('click',()=>{togglePromptAction(p.id,'save');renderPromptDetail();});app.querySelector('[data-add-collection]')?.addEventListener('click',()=>addPromptToCollection(p));app.querySelector('[data-report-prompt]')?.addEventListener('click',()=>reportItem('prompt',p.id,p.title));
  document.getElementById('promptCommentForm')?.addEventListener('submit',e=>{e.preventDefault();const u=requireUser('Yorum yapma');if(!u)return;const all=read(KEYS.promptComments,{});const list=all[p.slug]||[];list.unshift({id:uid('comment'),userId:u.id,author:u.name,text:new FormData(e.currentTarget).get('comment'),createdAt:now(),reports:[]});all[p.slug]=list;write(KEYS.promptComments,all);e.currentTarget.reset();renderPromptComments(p);});
  app.onclick=async e=>{const like=e.target.closest('[data-prompt-like]'),save=e.target.closest('[data-prompt-save]'),copy=e.target.closest('[data-prompt-copy]');if(like){togglePromptAction(like.dataset.promptLike,'like');renderPromptDetail();}if(save){togglePromptAction(save.dataset.promptSave,'save');renderPromptDetail();}if(copy){const q=findPrompt(copy.dataset.promptCopy);if(q)await copyPrompt(q,'quick',Object.fromEntries(q.variables.map(v=>[v.key,v.default])));}};
}
function renderPromptComments(p){const wrap=document.getElementById('promptComments');if(!wrap)return;const list=(read(KEYS.promptComments,{})[p.slug]||[]).filter(x=>x.status!=='removed');wrap.innerHTML=list.map(c=>`<article class="comment-card"><div class="comment-avatar">${esc(initials(c.author))}</div><div><strong>${esc(c.author)}</strong><span>${esc(fmtDate(c.createdAt))}</span><p>${esc(c.text)}</p><button class="comment-link" data-report-comment="${attr(c.id)}">Raporla</button></div></article>`).join('')||'<div class="profile-empty-state">Henüz yorum yok.</div>';wrap.querySelectorAll('[data-report-comment]').forEach(btn=>btn.addEventListener('click',()=>reportItem('prompt-comment',btn.dataset.reportComment,p.slug)));}
function reportItem(type,itemId,context){const u=requireUser('Raporlama');if(!u)return;const reason=prompt('Raporlama nedenini kısa şekilde yaz:');if(!reason)return;const reports=read(KEYS.reports,[]);if(reports.some(r=>r.userId===u.id&&r.type===type&&String(r.itemId)===String(itemId))){toast('Bu içeriği daha önce raporladın.','error');return;}reports.unshift({id:uid('report'),userId:u.id,reporter:u.name,type,itemId:String(itemId),context,reason,createdAt:now(),status:'open'});write(KEYS.reports,reports);toast('Rapor yerel moderasyon kuyruğuna eklendi.');}
function addPromptToCollection(p){const u=requireUser('Koleksiyona ekleme');if(!u)return;let cols=read(KEYS.collections,[]).filter(c=>c.userId===u.id);let name;if(cols.length){name=prompt('Koleksiyon adı yaz. Mevcut: '+cols.map(c=>c.name).join(', '),cols[0].name);}else name=prompt('Yeni koleksiyon adı:','Favori Promptlar');if(!name)return;let all=read(KEYS.collections,[]);let col=all.find(c=>c.userId===u.id&&c.name.toLowerCase()===name.toLowerCase());if(!col){col={id:uid('collection'),userId:u.id,name:name.trim(),promptIds:[],createdAt:now()};all.push(col);}if(!col.promptIds.includes(String(p.id)))col.promptIds.push(String(p.id));write(KEYS.collections,all);toast('Prompt koleksiyona eklendi.');}

function initStandaloneBuilder(){const selector=document.getElementById('builderPromptSelect'),app=document.getElementById('builderApp');if(!selector||!app)return;const list=combinedPrompts();selector.innerHTML=list.map(p=>`<option value="${attr(p.slug)}">${esc(categoryLabel(p.category))} — ${esc(p.title)}</option>`).join('');const query=new URLSearchParams(location.search).get('slug');if(query&&findPrompt(query))selector.value=query;const show=()=>{const p=findPrompt(selector.value)||list[0];app.innerHTML=builderMarkup(p,true);bindBuilder(app,p);};selector.addEventListener('change',show);show();}

function renderHome(){
  const settings=read(KEYS.settings,{});const weekly=findPrompt(settings.weeklyPromptId)||DATA.prompts.find(p=>p.weekly)||DATA.prompts[0];const box=document.getElementById('weeklyPrompt');if(box&&weekly)box.innerHTML=`<div class="weekly-prompt-image"><img src="${attr(path(weekly.thumbnail))}" loading="lazy" width="640" height="360" alt="${attr(weekly.title)}"></div><div><span class="eyebrow">HAFTANIN PROMPTU</span><h2>${esc(weekly.title)}</h2><p>${esc(weekly.description)}</p><div class="prompt-model-tags">${weekly.models.slice(0,4).map(x=>`<span>${esc(x)}</span>`).join('')}</div><div class="hero-buttons"><a class="btn" href="${attr(promptUrl(weekly))}">Promptu Aç</a><a class="btn btn-secondary" href="${attr(page('prompt-builder.html?slug='+weekly.slug))}">Builder’da Kullan</a></div></div>`;
  const featured=document.getElementById('featuredPromptGrid');if(featured)featured.innerHTML=combinedPrompts().filter(p=>p.featured).slice(0,6).map(promptCard).join('');
  const stats=document.getElementById('platformStats');if(stats)stats.innerHTML=`<div><strong>${combinedPrompts().length}</strong><span>Profesyonel prompt</span></div><div><strong>${Object.keys(DATA.categories).length}</strong><span>Ana kategori</span></div><div><strong>${Object.keys(DATA.collections).length}</strong><span>Hazır koleksiyon</span></div><div><strong>3</strong><span>Prompt seviyesi</span></div>`;
}

function renderModels(){const table=document.getElementById('modelComparisonTable');if(!table)return;table.innerHTML=`<div class="comparison-table-wrap"><table class="comparison-table"><thead><tr><th>Model / araç</th><th>En güçlü alan</th><th>Bağlam</th><th>Görsel</th><th>Kod</th><th>Türkçe</th><th></th></tr></thead><tbody>${DATA.models.map(m=>`<tr><td><strong>${esc(m.name)}</strong></td><td>${esc(m.best)}</td><td>${esc(m.context)}</td><td>${esc(m.image)}</td><td>${esc(m.code)}</td><td>${esc(m.tr)}</td><td><a class="mini-action-btn" href="${attr(page(m.link))}">İncele</a></td></tr>`).join('')}</tbody></table></div>`;}

function renderCollections(){const app=document.getElementById('collectionsApp');if(!app)return;const ready=Object.entries(DATA.collections).map(([name,ids])=>({name,ids,local:false}));const u=currentUser();const custom=u?read(KEYS.collections,[]).filter(c=>c.userId===u.id).map(c=>({name:c.name,ids:c.promptIds,local:true,id:c.id})):[];const all=[...ready,...custom];app.innerHTML=`<div class="collection-grid">${all.map(c=>`<article class="collection-card"><span class="collection-count">${c.ids.length} prompt</span><h2>${esc(c.name)}</h2><p>${c.local?'Kendi oluşturduğun yerel koleksiyon.':'Belirli bir iş akışı için seçilmiş hazır prompt paketi.'}</p><div class="collection-mini-prompts">${c.ids.slice(0,3).map(id=>{const p=findPrompt(id);return p?`<a href="${attr(promptUrl(p))}">${esc(p.title)}</a>`:'';}).join('')}</div><button class="btn" data-open-collection="${attr(c.name)}" type="button">Koleksiyonu Aç</button>${c.local?`<button class="mini-action-btn" data-delete-collection="${attr(c.id)}" type="button">Sil</button>`:''}</article>`).join('')}</div><section id="collectionPromptList" class="collection-prompt-list"></section>`;app.querySelectorAll('[data-open-collection]').forEach(btn=>btn.addEventListener('click',()=>{const c=all.find(x=>x.name===btn.dataset.openCollection);const prompts=c.ids.map(findPrompt).filter(Boolean);document.getElementById('collectionPromptList').innerHTML=`<div class="section-heading"><span class="eyebrow">KOLEKSİYON</span><h2>${esc(c.name)}</h2></div><div class="prompt-grid-modern">${prompts.map(promptCard).join('')}</div>`;document.getElementById('collectionPromptList').scrollIntoView({behavior:'smooth'});}));app.querySelectorAll('[data-delete-collection]').forEach(btn=>btn.addEventListener('click',()=>{if(!confirm('Koleksiyon silinsin mi?'))return;write(KEYS.collections,read(KEYS.collections,[]).filter(c=>c.id!==btn.dataset.deleteCollection));renderCollections();}));}

function fileToData(file){return new Promise((resolve,reject)=>{if(!file)return resolve('');if(file.size>2*1024*1024)return reject(new Error('Görsel 2 MB sınırını aşıyor.'));const r=new FileReader();r.onload=()=>resolve(r.result);r.onerror=reject;r.readAsDataURL(file);});}
function postTypeLabel(t){return ({prompt:'Prompt Paylaşımı',output:'AI Çıktısı',question:'Soru',tip:'İpucu',comparison:'Karşılaştırma',general:'Topluluk'})[t]||'Topluluk';}
function renderSocialPost(p,u){
  const liked=Boolean(u&&Array.isArray(p.likes)&&p.likes.includes(u.id));
  const saved=Boolean(u&&Array.isArray(p.saves)&&p.saves.includes(u.id));
  const comments=(p.comments||[]).filter(c=>c.status!=='removed');
  const promptBlock=p.promptText ? `<details class="post-prompt-details"><summary>Kullanılan promptu göster</summary><pre>${esc(p.promptText)}</pre><button class="mini-action-btn" data-copy-post-prompt="${attr(p.id)}">Kopyala / Remix</button></details>` : '';
  const outputBlock=p.outputText ? `<div class="post-output-box"><strong>Çıktı / sonuç</strong><p>${esc(p.outputText)}</p></div>` : '';
  const imageBlock=p.image ? `<a href="${attr(path(p.image))}" target="_blank" rel="noopener" class="post-image-link"><img src="${attr(path(p.image))}" alt="Paylaşım görseli" class="post-image" loading="lazy"></a>` : '';
  const deleteButton=u&&(u.role==='admin'||u.id===p.userId) ? `<button class="mini-action-btn post-admin-delete" data-social-delete="${attr(p.id)}">Sil</button>` : '';
  const commentHtml=comments.map(c=>`<div class="inline-comment"><strong>${esc(c.author)}</strong><p>${esc(c.text)}</p><button data-report-post-comment="${attr(c.id)}" data-post="${attr(p.id)}">Raporla</button></div>`).join('');
  return `<article class="post-card" data-post-id="${attr(p.id)}">
    <div class="post-avatar"><span>${esc(initials(p.author))}</span></div>
    <div class="post-content">
      <div class="post-author">${esc(p.author)} <span>• ${esc(fmtDate(p.createdAt))}</span></div>
      <div class="post-badge">${esc(postTypeLabel(p.type))}${p.tool?' • '+esc(p.tool):''}</div>
      <p class="post-text">${esc(p.content)}</p>
      ${promptBlock}${outputBlock}${imageBlock}
      <div class="post-actions social-post-actions">
        <button class="mini-action-btn ${liked?'active':''}" data-social-like="${attr(p.id)}">♡ <span>${(p.likes||[]).length}</span></button>
        <button class="mini-action-btn ${saved?'active':''}" data-social-save="${attr(p.id)}">☆ <span>${(p.saves||[]).length}</span></button>
        <button class="mini-action-btn" data-toggle-comments="${attr(p.id)}">Yorum ${comments.length}</button>
        <button class="mini-action-btn" data-social-report="${attr(p.id)}">⚑</button>${deleteButton}
      </div>
      <div class="post-comments" id="comments-${attr(p.id)}" hidden>
        <form class="inline-comment-form" data-comment-form="${attr(p.id)}"><input name="comment" required placeholder="Yorum yaz..."><button type="submit">Gönder</button></form>
        ${commentHtml}
      </div>
    </div>
  </article>`;
}
function renderSocial(){
  const feed=document.getElementById('socialFeed');
  if(!feed)return;
  const posts=read(KEYS.posts,[]).filter(p=>p.status!=='removed');
  const u=currentUser();
  const header='<div class="feed-header"><h2>Topluluk Akışı</h2><p class="admin-muted">Prompt, çıktı, ipucu ve karşılaştırma paylaş.</p></div>';
  feed.innerHTML=header+(posts.map(p=>renderSocialPost(p,u)).join('')||'<div class="profile-empty-state">Henüz paylaşım yok.</div>');
}
function initSocial(){renderSocial();const modal=document.getElementById('createModal');const btn=document.getElementById('createPostBtn');btn?.addEventListener('click',()=>{if(!requireUser('Paylaşım yapma'))return;window.openCreateModal();});const draft=readSessionDraft();if(draft||new URLSearchParams(location.search).get('create')==='1'){if(currentUser()){window.openCreateModal();if(draft)fillSocialDraft(draft);}}
  const imageInput=document.getElementById('postImageInput');imageInput?.addEventListener('change',async()=>{try{const data=await fileToData(imageInput.files[0]);const img=document.getElementById('postImagePreview');img.src=data;document.getElementById('postImagePreviewWrap').classList.add('show');document.getElementById('postImageFileName').textContent=imageInput.files[0].name;}catch(e){toast(e.message,'error');window.clearSocialImage();}});
  document.getElementById('socialCreateForm')?.addEventListener('submit',async e=>{e.preventDefault();const u=requireUser('Paylaşım yapma');if(!u)return;const fd=new FormData(e.currentTarget);let image='';try{image=await fileToData(document.getElementById('postImageInput')?.files[0]);}catch(err){toast(err.message,'error');return;}const content=String(fd.get('content')||'').trim();if(!content&&!image){toast('Metin veya görsel eklemelisin.','error');return;}const posts=read(KEYS.posts,[]);posts.unshift({id:uid('post'),userId:u.id,author:u.name,type:String(fd.get('type')||'general'),content,tool:String(fd.get('tool')||''),promptId:String(fd.get('promptId')||'')||null,promptText:String(fd.get('promptText')||''),outputText:String(fd.get('outputText')||''),image,likes:[],saves:[],reports:[],status:'active',createdAt:now(),comments:[]});write(KEYS.posts,posts);e.currentTarget.reset();window.clearSocialImage();window.closeCreateModal();toast('Paylaşım oluşturuldu.');renderSocial();});
  feedEventBindings();
}
function readSessionDraft(){try{const s=sessionStorage.getItem('promptla_share_draft');if(!s)return null;sessionStorage.removeItem('promptla_share_draft');return JSON.parse(s);}catch(e){return null;}}
function fillSocialDraft(d){const f=document.getElementById('socialCreateForm');if(!f)return;f.elements.type.value='prompt';f.elements.content.value=d.content||'';f.elements.tool.value=d.tool||'';f.elements.promptId.value=d.promptId||'';f.elements.promptText.value=d.promptText||'';}
function feedEventBindings(){const feed=document.getElementById('socialFeed');if(!feed)return;feed.onclick=async e=>{const posts=read(KEYS.posts,[]);const u=currentUser();const action=(id,fn)=>{const p=posts.find(x=>x.id===id);if(!p)return;fn(p);write(KEYS.posts,posts);renderSocial();};const like=e.target.closest('[data-social-like]');if(like){const user=requireUser('Beğenme');if(!user)return;action(like.dataset.socialLike,p=>{p.likes=p.likes||[];p.likes=p.likes.includes(user.id)?p.likes.filter(x=>x!==user.id):[...p.likes,user.id];});}const save=e.target.closest('[data-social-save]');if(save){const user=requireUser('Kaydetme');if(!user)return;action(save.dataset.socialSave,p=>{p.saves=p.saves||[];p.saves=p.saves.includes(user.id)?p.saves.filter(x=>x!==user.id):[...p.saves,user.id];});}const toggle=e.target.closest('[data-toggle-comments]');if(toggle){const box=document.getElementById('comments-'+toggle.dataset.toggleComments);if(box)box.hidden=!box.hidden;}const del=e.target.closest('[data-social-delete]');if(del&&confirm('Gönderi silinsin mi?')){action(del.dataset.socialDelete,p=>p.status='removed');}const report=e.target.closest('[data-social-report]');if(report)reportItem('post',report.dataset.socialReport,'topluluk');const rpc=e.target.closest('[data-report-post-comment]');if(rpc)reportItem('post-comment',rpc.dataset.reportPostComment,rpc.dataset.post);const cp=e.target.closest('[data-copy-post-prompt]');if(cp){const p=posts.find(x=>x.id===cp.dataset.copyPostPrompt);if(p?.promptText){await window.promptlaCopyText(p.promptText);const user=requireUser('Remix kaydetme');if(user){const remixes=read(KEYS.remixes,[]);remixes.unshift({id:uid('remix'),userId:user.id,promptId:p.promptId||null,title:'Topluluk Remix',content:p.promptText,values:{},version:'community',createdAt:now()});write(KEYS.remixes,remixes);toast('Prompt kopyalandı ve remix olarak kaydedildi.');}}}};
  feed.onsubmit=e=>{const form=e.target.closest('[data-comment-form]');if(!form)return;e.preventDefault();const u=requireUser('Yorum yapma');if(!u)return;const posts=read(KEYS.posts,[]);const p=posts.find(x=>x.id===form.dataset.commentForm);if(!p)return;const text=new FormData(form).get('comment');p.comments.unshift({id:uid('comment'),userId:u.id,author:u.name,text,createdAt:now(),status:'active'});write(KEYS.posts,posts);renderSocial();};
}

function renderProfile(){const app=document.getElementById('profileApp');if(!app)return;const u=currentUser();if(!u){app.innerHTML=`<div class="profile-empty-state"><h2>Profil için giriş yap</h2><p>Kaydedilen promptlar, remixler ve koleksiyonlar bu tarayıcıdaki hesabına bağlanır.</p><button class="btn" onclick="openAuthModal('login')">Giriş Yap</button></div>`;return;}const saved=userSet(KEYS.saves,u.id);const savedPrompts=combinedPrompts().filter(p=>saved.has(String(p.id)));const remixes=read(KEYS.remixes,[]).filter(r=>r.userId===u.id);const cols=read(KEYS.collections,[]).filter(c=>c.userId===u.id);const posts=read(KEYS.posts,[]).filter(p=>p.userId===u.id&&p.status!=='removed');app.innerHTML=`<section class="profile-hero"><div class="profile-avatar-lg">${esc(initials(u.name))}</div><div><span class="eyebrow">YEREL PROFİL</span><h1>${esc(u.name)}</h1><p>${esc(u.bio||'Henüz profil açıklaması eklenmedi.')}</p><span>${esc(u.email)} • ${esc(u.role)}</span></div><div class="profile-hero-actions"><button class="mini-action-btn" data-edit-profile>Profili Düzenle</button>${u.role==='admin'?`<a class="btn" href="${page('admin.html')}">Yerel Yönetim</a>`:''}</div></section><div class="profile-tabs profile-tabs-v2"><button class="active" data-profile-tab="saved">Kaydedilenler (${savedPrompts.length})</button><button data-profile-tab="remixes">Remixler (${remixes.length})</button><button data-profile-tab="collections">Koleksiyonlar (${cols.length})</button><button data-profile-tab="posts">Paylaşımlarım (${posts.length})</button></div><section id="profileTabContent"></section>`;const content=document.getElementById('profileTabContent');const show=tab=>{app.querySelectorAll('[data-profile-tab]').forEach(b=>b.classList.toggle('active',b.dataset.profileTab===tab));if(tab==='saved')content.innerHTML=`<div class="prompt-grid-modern">${savedPrompts.map(promptCard).join('')||'<div class="profile-empty-state">Henüz prompt kaydetmedin.</div>'}</div>`;if(tab==='remixes')content.innerHTML=remixes.map(r=>`<article class="detail-card remix-card"><span class="eyebrow">${esc(activeVersionLabel(r.version))}</span><h2>${esc(r.title)}</h2><pre>${esc(r.content)}</pre><div><button class="mini-action-btn" data-copy-remix="${attr(r.id)}">Kopyala</button><button class="mini-action-btn" data-delete-remix="${attr(r.id)}">Sil</button></div></article>`).join('')||'<div class="profile-empty-state">Henüz özel sürüm kaydetmedin.</div>';if(tab==='collections')content.innerHTML=`<div class="profile-collection-tools"><button class="btn" data-new-collection>Yeni Koleksiyon</button></div>${cols.map(c=>`<article class="detail-card"><h2>${esc(c.name)}</h2><p>${c.promptIds.length} prompt</p><button class="mini-action-btn" data-open-profile-collection="${attr(c.id)}">Görüntüle</button></article>`).join('')||'<div class="profile-empty-state">Henüz koleksiyon oluşturmadın.</div>'}`;if(tab==='posts')content.innerHTML=posts.map(p=>`<article class="detail-card"><span class="eyebrow">${esc(postTypeLabel(p.type))}</span><p>${esc(p.content)}</p><small>${esc(fmtDate(p.createdAt))}</small></article>`).join('')||'<div class="profile-empty-state">Henüz paylaşım yapmadın.</div>';};show('saved');app.querySelectorAll('[data-profile-tab]').forEach(b=>b.addEventListener('click',()=>show(b.dataset.profileTab)));app.querySelector('[data-edit-profile]')?.addEventListener('click',()=>{const name=prompt('Ad Soyad',u.name);if(!name)return;const bio=prompt('Kısa profil açıklaması',u.bio||'');const users=getUsers();const target=users.find(x=>x.id===u.id);target.name=name.trim();target.bio=String(bio||'').trim();setUsers(users);renderHeader();renderProfile();});content.onclick=async e=>{const cr=e.target.closest('[data-copy-remix]');if(cr){const r=remixes.find(x=>x.id===cr.dataset.copyRemix);if(r)await window.promptlaCopyText(r.content);}const dr=e.target.closest('[data-delete-remix]');if(dr&&confirm('Remix silinsin mi?')){write(KEYS.remixes,read(KEYS.remixes,[]).filter(r=>r.id!==dr.dataset.deleteRemix));renderProfile();}if(e.target.closest('[data-new-collection]')){const name=prompt('Koleksiyon adı');if(name){const all=read(KEYS.collections,[]);all.push({id:uid('collection'),userId:u.id,name:name.trim(),promptIds:[],createdAt:now()});write(KEYS.collections,all);renderProfile();}}const oc=e.target.closest('[data-open-profile-collection]');if(oc){location.href=page('koleksiyonlar.html');}};}

function renderAdmin(){const app=document.getElementById('adminApp');if(!app)return;const u=currentUser();if(!u||u.role!=='admin'){app.innerHTML=`<div class="profile-empty-state"><h2>Yerel yönetici girişi gerekli</h2><p>Bu statik sürümde yönetim yalnızca mevcut tarayıcı verilerini düzenler. Otomatik e-posta yetkilendirmesi yoktur.</p><code>${esc(DEMO_ADMIN.email)} / ${esc(DEMO_ADMIN.password)}</code><button class="btn" onclick="openAuthModal('login')">Giriş Yap</button></div>`;return;}const reports=read(KEYS.reports,[]),messages=read(KEYS.messages,[]),custom=read(KEYS.customPrompts,[]),deleted=read(KEYS.deletedPrompts,[]),users=getUsers();app.innerHTML=`<div class="admin-stat-grid"><div><strong>${combinedPrompts().length}</strong><span>Aktif prompt</span></div><div><strong>${custom.length}</strong><span>Yerel prompt</span></div><div><strong>${reports.filter(r=>r.status==='open').length}</strong><span>Açık rapor</span></div><div><strong>${messages.length}</strong><span>Mesaj</span></div></div><div class="admin-tabs-v2"><button class="active" data-admin-tab="prompts">Prompt Yönetimi</button><button data-admin-tab="moderation">Moderasyon</button><button data-admin-tab="users">Kullanıcılar</button><button data-admin-tab="messages">Mesajlar</button><button data-admin-tab="settings">Ayarlar</button></div><section id="adminTabContent"></section>`;const content=document.getElementById('adminTabContent');const show=tab=>{app.querySelectorAll('[data-admin-tab]').forEach(b=>b.classList.toggle('active',b.dataset.adminTab===tab));if(tab==='prompts')content.innerHTML=`<section class="detail-card admin-form-card"><h2>Yerel Prompt Ekle</h2><form id="localPromptForm" class="admin-form"><div class="admin-two-col"><label>Başlık<input name="title" required></label><label>Kategori<select name="category">${Object.entries(DATA.categories).map(([k,v])=>`<option value="${attr(k)}">${esc(v.label)}</option>`).join('')}</select></label></div><div class="admin-two-col"><label>Alt kategori<input name="subcategory" required></label><label>Modeller<input name="models" placeholder="ChatGPT, Claude"></label></div><label>Kısa açıklama<textarea name="description" required></textarea></label><label>Hızlı prompt<textarea name="quick" required></textarea></label><label>Gelişmiş prompt<textarea name="advanced" required></textarea></label><label>Uzman prompt<textarea name="expert" required></textarea></label><button class="btn" type="submit">Promptu Ekle</button></form></section><section class="detail-card"><h2>Aktif Promptlar</h2><div class="admin-prompt-list">${combinedPrompts().map(p=>`<div class="admin-mini-item"><div><strong>${esc(p.title)}</strong><span>${esc(categoryLabel(p.category))} • ${esc(p.subcategory)}</span></div><button class="admin-delete-btn" data-hide-prompt="${attr(p.id)}">${String(p.id).startsWith('custom')?'Sil':'Gizle'}</button></div>`).join('')}</div>${deleted.length?`<button class="mini-action-btn" data-restore-prompts>Gizlenen ${deleted.length} promptu geri getir</button>`:''}</section>`;if(tab==='moderation')content.innerHTML=`<section class="detail-card"><h2>Rapor Kuyruğu</h2>${reports.map(r=>`<div class="admin-mini-item"><div><strong>${esc(r.type)} • ${esc(r.context)}</strong><span>${esc(r.reporter)} • ${esc(fmtDate(r.createdAt))}</span><p>${esc(r.reason)}</p></div><select data-report-status="${attr(r.id)}"><option value="open" ${r.status==='open'?'selected':''}>Açık</option><option value="reviewed" ${r.status==='reviewed'?'selected':''}>İncelendi</option><option value="dismissed" ${r.status==='dismissed'?'selected':''}>Reddedildi</option><option value="removed" ${r.status==='removed'?'selected':''}>İçerik kaldırıldı</option></select></div>`).join('')||'<div class="profile-empty-state">Rapor yok.</div>'}</section>`;if(tab==='users')content.innerHTML=`<section class="detail-card"><h2>Yerel Kullanıcılar</h2>${users.map(x=>`<div class="admin-mini-item"><div><strong>${esc(x.name)}</strong><span>${esc(x.email)} • ${esc(x.role)}</span></div>${x.id!=='local-admin'?`<select data-user-role="${attr(x.id)}"><option value="user" ${x.role==='user'?'selected':''}>user</option><option value="admin" ${x.role==='admin'?'selected':''}>admin</option></select>`:'<span>Sistem yöneticisi</span>'}</div>`).join('')}</section>`;if(tab==='messages')content.innerHTML=`<section class="detail-card"><h2>İletişim Mesajları</h2>${messages.map(m=>`<div class="admin-mini-item"><div><strong>${esc(m.subject)} — ${esc(m.name)}</strong><span>${esc(m.email)} • ${esc(fmtDate(m.createdAt))}</span><p>${esc(m.message)}</p></div><button class="admin-delete-btn" data-delete-message="${attr(m.id)}">Sil</button></div>`).join('')||'<div class="profile-empty-state">Mesaj yok.</div>'}</section>`;if(tab==='settings'){const s=read(KEYS.settings,{});content.innerHTML=`<section class="detail-card admin-form-card"><h2>Yerel Site Ayarları</h2><form id="localSettingsForm" class="admin-form"><div class="admin-two-col"><label>Logo ana metni<input name="siteLogoText" value="${attr(s.siteLogoText||'PROMPT')}"></label><label>Logo vurgu<input name="siteLogoAccent" value="${attr(s.siteLogoAccent||'LA')}"></label></div><label>Haftanın promptu<select name="weeklyPromptId">${combinedPrompts().map(p=>`<option value="${attr(p.id)}" ${String(s.weeklyPromptId)===String(p.id)?'selected':''}>${esc(p.title)}</option>`).join('')}</select></label><button class="btn" type="submit">Ayarları Kaydet</button><button class="admin-delete-btn" type="button" data-reset-demo>Tüm Yerel Demo Verisini Sıfırla</button></form></section>`;}bindAdminTab(tab);};show('prompts');app.querySelectorAll('[data-admin-tab]').forEach(b=>b.addEventListener('click',()=>show(b.dataset.adminTab)));}
function bindAdminTab(tab){const content=document.getElementById('adminTabContent');if(!content)return;if(tab==='prompts'){document.getElementById('localPromptForm')?.addEventListener('submit',e=>{e.preventDefault();const fd=new FormData(e.currentTarget);const title=String(fd.get('title'));const list=read(KEYS.customPrompts,[]);const id='custom-'+Date.now();list.unshift({id,slug:title.toLocaleLowerCase('tr-TR').replace(/[çğıöşü]/g,c=>({ç:'c',ğ:'g',ı:'i',ö:'o',ş:'s',ü:'u'}[c])).replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'')+'-'+Date.now().toString(36),title,category:String(fd.get('category')),categoryLabel:categoryLabel(fd.get('category')),subcategory:String(fd.get('subcategory')),description:String(fd.get('description')),models:String(fd.get('models')||'ChatGPT').split(',').map(x=>x.trim()).filter(Boolean),level:'Orta',tags:['yerel','özel'],variables:[],versions:{quick:String(fd.get('quick')),advanced:String(fd.get('advanced')),expert:String(fd.get('expert'))},constraints:'Kullanıcı tarafından eklenen yerel prompt.',outputFormat:'İstenen görev biçimi',before:'Kısa ve belirsiz istek',after:String(fd.get('expert')),image:'images/urun1.webp',thumbnail:'images/thumbs/urun1-thumb.webp',collections:[],featured:false,weekly:false,createdAt:now().slice(0,10),version:'1.0'});write(KEYS.customPrompts,list);toast('Yerel prompt eklendi.');renderAdmin();});content.querySelectorAll('[data-hide-prompt]').forEach(btn=>btn.addEventListener('click',()=>{const id=btn.dataset.hidePrompt;if(String(id).startsWith('custom'))write(KEYS.customPrompts,read(KEYS.customPrompts,[]).filter(p=>String(p.id)!==String(id)));else{const d=read(KEYS.deletedPrompts,[]);if(!d.includes(String(id)))d.push(String(id));write(KEYS.deletedPrompts,d);}renderAdmin();}));content.querySelector('[data-restore-prompts]')?.addEventListener('click',()=>{write(KEYS.deletedPrompts,[]);renderAdmin();});}if(tab==='moderation')content.querySelectorAll('[data-report-status]').forEach(sel=>sel.addEventListener('change',()=>{const list=read(KEYS.reports,[]);const r=list.find(x=>x.id===sel.dataset.reportStatus);if(r){r.status=sel.value;write(KEYS.reports,list);toast('Moderasyon durumu güncellendi.');}}));if(tab==='users')content.querySelectorAll('[data-user-role]').forEach(sel=>sel.addEventListener('change',()=>{const users=getUsers();const x=users.find(u=>u.id===sel.dataset.userRole);if(x){x.role=sel.value;setUsers(users);toast('Rol güncellendi.');}}));if(tab==='messages')content.querySelectorAll('[data-delete-message]').forEach(btn=>btn.addEventListener('click',()=>{write(KEYS.messages,read(KEYS.messages,[]).filter(m=>m.id!==btn.dataset.deleteMessage));renderAdmin();}));if(tab==='settings'){document.getElementById('localSettingsForm')?.addEventListener('submit',e=>{e.preventDefault();const fd=new FormData(e.currentTarget);write(KEYS.settings,{...read(KEYS.settings,{}),siteLogoText:String(fd.get('siteLogoText')),siteLogoAccent:String(fd.get('siteLogoAccent')),weeklyPromptId:String(fd.get('weeklyPromptId'))});toast('Ayarlar kaydedildi.');renderHeader();});content.querySelector('[data-reset-demo]')?.addEventListener('click',()=>{if(!confirm('Tüm yerel hesap, beğeni, kayıt, paylaşım ve ayarlar sıfırlansın mı?'))return;Object.values(KEYS).forEach(k=>localStorage.removeItem(k));seed();toast('Yerel demo verisi sıfırlandı.');renderHeader();renderAdmin();});}}

function bindContact(){document.querySelectorAll('#contactForm').forEach(form=>form.addEventListener('submit',e=>{e.preventDefault();const fd=new FormData(form);const list=read(KEYS.messages,[]);list.unshift({id:uid('message'),name:String(fd.get('name')),email:String(fd.get('email')),subject:String(fd.get('subject')),message:String(fd.get('message')),createdAt:now()});write(KEYS.messages,list);form.reset();toast('Mesaj bu tarayıcıdaki yönetim paneline kaydedildi.');}));}
function bindPageAuth(){document.getElementById('pageLoginForm')?.addEventListener('submit',e=>{e.preventDefault();const fd=new FormData(e.currentTarget);if(login(fd.get('email'),fd.get('password'))){toast('Giriş yapıldı.');location.href=page('profil.html');}else toast('E-posta veya şifre hatalı.','error');});document.getElementById('pageRegisterForm')?.addEventListener('submit',e=>{e.preventDefault();const fd=new FormData(e.currentTarget);const r=register(String(fd.get('name')),String(fd.get('email')),String(fd.get('password')));if(r.ok){toast('Hesap oluşturuldu.');location.href=page('profil.html');}else toast(r.message,'error');});}


function bindGlobalPromptActions(){
  if(PAGE==='prompts'||PAGE==='prompt-detail') return;
  document.addEventListener('click',async e=>{
    const like=e.target.closest('[data-prompt-like]');
    const save=e.target.closest('[data-prompt-save]');
    const copy=e.target.closest('[data-prompt-copy]');
    if(like){togglePromptAction(like.dataset.promptLike,'like');if(PAGE==='home')renderHome();if(PAGE==='collections')renderCollections();if(PAGE==='profile')renderProfile();}
    if(save){togglePromptAction(save.dataset.promptSave,'save');if(PAGE==='home')renderHome();if(PAGE==='collections')renderCollections();if(PAGE==='profile')renderProfile();}
    if(copy){const p=findPrompt(copy.dataset.promptCopy);if(p)await copyPrompt(p,'quick',Object.fromEntries(p.variables.map(v=>[v.key,v.default])));}
  });
}

function renderCurrentPage(){if(PAGE==='profile')renderProfile();if(PAGE==='admin')renderAdmin();}
function boot(){seed();renderAuthModal();renderHeader();bindContact();bindPageAuth();bindGlobalPromptActions();if(PAGE==='home')renderHome();if(PAGE==='prompts')initPromptLibrary();if(PAGE==='prompt-detail')renderPromptDetail();if(PAGE==='builder')initStandaloneBuilder();if(PAGE==='collections')renderCollections();if(PAGE==='social')initSocial();if(PAGE==='profile')renderProfile();if(PAGE==='admin')renderAdmin();if(PAGE==='models')renderModels();}

document.addEventListener('DOMContentLoaded',boot);
})();
